package com.ratelimit.core;

/**
 * 限流算法类型枚举
 */
public enum RateLimitAlgorithm {
    /** 令牌桶 - 支持突发流量，精确度高 */
    TOKEN_BUCKET,

    /** 滑动窗口日志 - 最精确但内存占用高 */
    SLIDING_WINDOW_LOG,

    /** 滑动窗口计数器 - 平衡精确度和性能 */
    SLIDING_WINDOW_COUNTER,

    /** 漏桶 - 流量平滑，强制均匀输出 */
    LEAKY_BUCKET,

    /** 固定窗口 - 最简单但边界有问题 */
    FIXED_WINDOW
}
```

