package com.ratelimit.config;

import lombok.Data;
import java.io.Serializable;

/**
 * 限流配置实体
 */
@Data
public class RateLimitConfig implements Serializable {
    private static final long serialVersionUID = 1L;

    /** 限流key前缀 */
    private String keyPrefix = "rate_limit";

    /** 限流算法 */
    private RateLimitAlgorithm algorithm = RateLimitAlgorithm.SLIDING_WINDOW_COUNTER;

    /** 限流维度 */
    private RateLimitDimension dimension = RateLimitDimension.API;

    /** 时间窗口大小(毫秒) */
    private long windowSizeMs = 1000;

    /** 时间窗口内最大请求数 */
    private long maxRequests = 100;

    /** 令牌桶容量 */
    private long bucketCapacity = 100;

    /** 令牌补充速率(每秒) */
    private double refillRate = 10.0;

    /** 是否启用本地缓存 */
    private boolean enableLocalCache = true;

    /** 本地缓存TTL(毫秒) */
    private long localCacheTtlMs = 100;

    /** 是否启用预热 */
    private boolean enableWarmup = false;

    /** 预热时间(秒) */
    private int warmupSeconds = 10;

    /** 限流后的等待策略 */
    private BlockStrategy blockStrategy = BlockStrategy.THROW_EXCEPTION;

    /** 是否集群限流 */
    private boolean clusterLimit = true;

    /** 降级时是否放行 */
    private boolean degradePass = false;

    /** 降级阈值(Redis不可用次数) */
    private int degradeThreshold = 3;

    public enum BlockStrategy {
        /** 直接抛出异常 */
        THROW_EXCEPTION,

        /** 等待重试 */
        WAIT_AND_RETRY,

        /** 返回特殊响应 */
        RETURN_FALSE
    }

    /**
     * 创建默认配置
     */
    public static RateLimitConfig defaultConfig() {
        RateLimitConfig config = new RateLimitConfig();
        config.setAlgorithm(RateLimitAlgorithm.SLIDING_WINDOW_COUNTER);
        config.setWindowSizeMs(1000);
        config.setMaxRequests(100);
        return config;
    }

    /**
     * 创建令牌桶配置
     */
    public static RateLimitConfig tokenBucketConfig(long capacity, double refillRate) {
        RateLimitConfig config = new RateLimitConfig();
        config.setAlgorithm(RateLimitAlgorithm.TOKEN_BUCKET);
        config.setBucketCapacity(capacity);
        config.setRefillRate(refillRate);
        return config;
    }
}
