#### 方案二：并行化调用改造

```java
// 优化前：串行调用
@Service
public class OrderServiceBad {

    public OrderDetail getOrderDetail(Long orderId) {
        // 串行调用，总耗时 = 300ms
        User user = userService.getUser(order.getUserId());      // 100ms
        List<Product> products = productService.getProducts(      // 100ms
            order.getProductIds()
        );
        Logistics logistics = logisticsService.getLogistics(      // 100ms
            order.getLogisticsId()
        );

        return assembleOrderDetail(order, user, products, logistics);
    }
}

// 优化后：并行调用
@Service
public class OrderServiceGood {

    @Autowired
    private AsyncExecutor asyncExecutor;  // 自定义线程池

    public OrderDetail getOrderDetail(Long orderId) {
        // 并行调用，总耗时 = 100ms

        CompletableFuture<User> userFuture = asyncExecutor
            .supplyAsync(() -> userService.getUser(order.getUserId()));

        CompletableFuture<List<Product>> productsFuture = asyncExecutor
            .supplyAsync(() -> productService.getProducts(order.getProductIds()));

        CompletableFuture<Logistics> logisticsFuture = asyncExecutor
            .supplyAsync(() -> logisticsService.getLogistics(order.getLogisticsId()));

        // 等待所有结果
        CompletableFuture.allOf(userFuture, productsFuture, logisticsFuture).join();

        return assembleOrderDetail(
            order,
            userFuture.get(),
            productsFuture.get(),
            logisticsFuture.get()
        );
    }
}

// 线程池配置
@Configuration
public class AsyncConfig {

    @Bean("asyncExecutor")
    public ThreadPoolTaskExecutor asyncExecutor() {
        ThreadPoolTaskExecutor executor = new ThreadPoolTaskExecutor();
        executor.setCorePoolSize(10);
        executor.setMaxPoolSize(50);
        executor.setQueueCapacity(100);
        executor.setThreadNamePrefix("async-");
        executor.setRejectedExecutionHandler(new CallerRunsPolicy());
        executor.initialize();
        return executor;
    }
}
```

