```java
// 缓存实现示例
@Service
public class CacheService {

    @Autowired
    private StringRedisTemplate redisTemplate;

    // 布隆过滤器防止缓存穿透
    @Autowired
    private BloomFilter<String> bloomFilter;

    public String getWithProtection(String key, Supplier<String> loader) {
        // 1. 检查布隆过滤器
        if (!bloomFilter.mightContain(key)) {
            return loader.get(); // 透传到数据库
        }

        // 2. 尝试从缓存获取
        String cached = redisTemplate.opsForValue().get(key);
        if (cached != null) {
            return cached;
        }

        // 3. 加锁防止缓存击穿
        String lockKey = "lock:" + key;
        String lockValue = UUID.randomUUID().toString();

        try {
            Boolean acquired = redisTemplate.opsForValue()
                .setIfAbsent(lockKey, lockValue, Duration.ofSeconds(10));

            if (Boolean.TRUE.equals(acquired)) {
                try {
                    // 双重检查
                    cached = redisTemplate.opsForValue().get(key);
                    if (cached != null) {
                        return cached;
                    }

                    // 加载数据
                    cached = loader.get();

                    // 随机过期时间防止雪崩
                    int baseTtl = 3600;
                    int jitter = ThreadLocalRandom.current().nextInt(300);
                    redisTemplate.opsForValue().set(key, cached, 
                        Duration.ofSeconds(baseTtl + jitter));

                    return cached;
                } finally {
                    redisTemplate.delete(lockKey);
                }
            } else {
                // 等待其他线程加载
                Thread.sleep(50);
                return redisTemplate.opsForValue().get(key);
            }
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
            return loader.get();
        }
    }
}
