// 限流注解
@Aspect
@Component
public class RateLimitAspect {

    @Autowired
    private SentinelResourceHolder holder;

    @Around("@annotation(RateLimiter)")
    public Object around(ProceedingJoinPoint pjp, RateLimiter limiter) throws Throwable {
        String resource = getResourceName(pjp);
        int threshold = limiter.qps();

        // 滑动窗口限流实现
        RateLimiter limiter = RateLimiterRegistry.get(resource);
        if (!limiter.tryAcquire(threshold)) {
            throw new BizException("系统繁忙，请稍后重试");
        }

        return pjp.proceed();
    }
}

